const ticket = $input.all()[0].json;
const subject = (ticket.subject || '').toLowerCase();
const body = (ticket.body || '').toLowerCase();
const text = subject + ' ' + body;

// Simple keyword-based routing
let category = 'general';
let priority = 'normal';

if (text.includes('billing') || text.includes('invoice') || text.includes('payment') || text.includes('charge')) {
  category = 'billing';
  priority = 'high';
} else if (text.includes('urgent') || text.includes('down') || text.includes('outage') || text.includes('crash')) {
  category = 'incident';
  priority = 'urgent';
} else if (text.includes('feature') || text.includes('request') || text.includes('add') || text.includes('new')) {
  category = 'feature-request';
  priority = 'low';
} else if (text.includes('password') || text.includes('login') || text.includes('access') || text.includes('account')) {
  category = 'account';
  priority = 'normal';
} else if (text.includes('bug') || text.includes('error') || text.includes('broken') || text.includes('not working')) {
  category = 'bug';
  priority = 'high';
}

return [{ json: { ...ticket, category, priority } }];
